import android.os.Bundle;
import androidx.appcompat.app.AppCompatActivity;

import java.util.HashMap;
import java.util.Map;

public class MainActivity extends AppCompatActivity {

    private Map<String, Double> accounts = new HashMap<>();

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        // Initialize some sample data for demonstration purposes
        accounts.put("Checking", 1000.0);
        accounts.put("Savings", 2000.0);
    }

    public void deposit(View view) {
        String accountName = ((EditText) findViewById(R.id.account_name)).getText().toString();
        double amount = Double.parseDouble(((EditText) findViewById(R.id.amount)).getText().toString());

        if (accounts.containsKey(accountName)) {
            accounts.put(accountName, accounts.get(accountName) + amount);
            Toast.makeText(this, "Deposit successful", Toast.LENGTH_SHORT).show();
        } else {
            Toast.makeText(this, "Invalid account name", Toast.LENGTH_SHORT).show();
        }
    }

    public void withdraw(View view) {
        String accountName = ((EditText) findViewById(R.id.account_name)).getText().toString();
        double amount = Double.parseDouble(((EditText) findViewById(R.id.amount)).getText().toString());

        if (accounts.containsKey(accountName)) {
            if (amount <= accounts.get(accountName)) {
                accounts.put(accountName, accounts.get(accountName) - amount);
                Toast.makeText(this, "Withdrawal successful", Toast.LENGTH_SHORT).show();
            } else {
                Toast.makeText(this, "Insufficient balance", Toast.LENGTH_SHORT).show();
            }
        } else {
            Toast.makeText(this, "Invalid account name", Toast.LENGTH_SHORT).show();
        }
    }

    public void displayBalance(View view) {
        String accountName = ((EditText) findViewById(R.id.account_name)).getText().toString();

        if (accounts.containsKey(accountName)) {
            Toast.makeText(this, "Account balance: " + accounts.get(accountName), Toast.LENGTH_SHORT).show();
        } else {
            Toast.makeText(this, "Invalid account name", Toast.LENGTH_SHORT).show();
        }
    }

    public void transactionHistory(View view) {
        StringBuilder history = new StringBuilder();

        for (Map.Entry<String, Double> entry : accounts.entrySet()) {
            history.append(entry.getKey()).append(": ").append(entry.getValue()).append("\n");
        }

        Toast.makeText(this, "Transaction History:\n" + history.toString(), Toast.LENGTH_SHORT).show();
    }
}